const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5001/api';

class ApiService {
  async request(endpoint, options = {}) {
    const url = `${API_BASE_URL}${endpoint}`;
    const config = {
      headers: { 'Content-Type': 'application/json', ...options.headers },
      ...options
    };
    try {
      const response = await fetch(url, config);
      const data = await response.json();
      if (!response.ok) throw new Error(data.message || 'API error');
      return data;
    } catch (error) {
      console.error(error);
      throw error;
    }
  }

  // Candidates
  getCandidates() { return this.request('/candidates'); }
  createCandidate(body) { return this.request('/candidates', { method: 'POST', body: JSON.stringify(body) }); }
  updateCandidate(id, body) { return this.request(`/candidates/${id}`, { method: 'PUT', body: JSON.stringify(body) }); }
  deleteCandidate(id) { return this.request(`/candidates/${id}`, { method: 'DELETE' }); }

  // Interviews
  getInterviews() { return this.request('/interviews'); }

  // Audit
  getAudit() { return this.request('/audit'); }
}

export default new ApiService();
